pub fn new() -> Self {
        Self {
            signals: Mutex::new(VecDeque::with_capacity(MAX_SIGNALS)),
        }
    }
pub fn record(&self, signal: GapSignal) {
        let mut signals = self.signals.lock().unwrap();
        if signals.len() >= MAX_SIGNALS {
            signals.pop_front();
        }
        signals.push_back(signal);
    }
